using System;

class Program
{
    static void Main()
    {
        // Calculate pi up to 5 decimals
        double pi = Math.PI;
        pi = Math.Round(pi, 5);

        // XOR the result twice
        byte[] bytes = BitConverter.GetBytes(pi);
