Here's an example of a blocking read that is interrupted by a signal, with EINTR handling:

```c
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <signal.h>
#include <errno.h>

void handle_signal(int signum) {
    printf("Caught signal %d\n", signum);
}

int main() {
    int fd = open("file.txt", O_RDONLY);
    if (fd == -1) {
        perror("open");
        exit(EXIT_FAILURE);
    }

    // Set up signal handler
    signal(SIGINT, handle_signal);

    // Perform blocking read
    char buffer[1024];
    ssize_t bytes_read = read(fd, buffer, sizeof(buffer)));
    if (bytes_read == -1) {
        if (errno == EINTR) {
            printf("Read interrupted by signal, retrying...\n");
            bytes_read = read(fd, buffer, sizeof(buffer)));
        } else {
            perror("read");
            exit(EXIT_FAILURE);
        }
    }

    // Print bytes read
    printf("Read %zd bytes\n", bytes_read);

    // Close file descriptor
    close(fd);

    return 0;
}
```

In this example, we open a file for reading, set up a signal handler for SIGINT, and perform a blocking read on the file descriptor.

If the read is interrupted by a signal, we check the error code to see if it's EINTR. If it is, we print a message indicating that the read was interrupted by a signal, and we retry the read.

If the read is not interrupted by a signal, we print the number of bytes read, and we close the file descriptor.

Overall, this example demonstrates how to handle a blocking read that is interrupted by a signal, using EINTR handling.

Here's an example C++ code that reads network packets from a socket on port 888:

```cpp
#include <iostream>
#include <cstring>
#include <sys/socket.h>
#include <netinet/in.h>
#include <arpa/inet.h>

int main() {
    // Create a socket
    int sockfd = socket(AF_INET, SOCK_DGRAM, 0);
    if (sockfd < 0) {
        std::cerr << "Error creating socket" << std::endl;
        return 1;
    }

    // Set up the socket address
    struct sockaddr_in server_addr;
    memset(&server_addr, 0, sizeof(server_addr));
    server_addr.sin_family = AF_INET;
    server_addr.sin_port = htons(888);
    server_addr.sin_addr.s_addr = INADDR_ANY;

    // Bind the socket to the server address
    if (bind(sockfd, (struct sockaddr*)&server_addr, sizeof(server_addr))) {
        std::cerr << "Error binding socket" << std::endl;
        return 1;
    }

    // Read network packets from the socket
    char buffer[1024];
    while (true) {
        int bytes_received = recv(sockfd, buffer, sizeof(buffer), 0);
        if (bytes_received < 0) {
            std::cerr << "Error receiving data" << std::endl;
            break;
        } else if (bytes_received == 0) {
            std::cerr << "Connection closed" << std::endl;
            break;
        } else {
            std::cout << "Received " << bytes_received << " bytes: " << std::string(buffer, bytes_received)) << std::endl;
        }
    }

    // Close the socket
    close(sockfd);

    return 0;
}
```

This code creates a socket on port 888, binds the socket to the server address, and then enters a loop to read network packets from the socket. The received packets are printed to the console. Finally, the socket is closed.

To create a rounded square shape in After Effects, you can use the following expression:

```
// Define the square size and corner radius
var squareSize = 500;
var cornerRadius = 50;

// Calculate the top right corner point
var topRightCorner = [squareSize - cornerRadius, 0];

// Calculate the top left corner point
var topLeftCorner = [0, 0];

// Calculate the bottom left corner point
var bottomLeftCorner = [0, squareSize - cornerRadius]];

// Calculate the bottom right corner point
var bottomRightCorner = [squareSize - cornerRadius, squareSize - cornerRadius]];

// Create an array of the corner points
var cornerPoints = [topLeftCorner, topRightCorner, bottomRightCorner, bottomLeftCorner]];

// Calculate the path points by adding the corner points
var pathPoints = [];
for (var I = 0; I < cornerPoints.length; i++) {
  var point = cornerPoints[i];
  pathPoints.push(point);
}

// Calculate the path segments by adding the corner points
var pathSegments = [];
for (var I = 0; I < cornerPoints.length - 1; i++) {
  var point1 = cornerPoints[i];
  var point2 = cornerPoints[i + 1]];
  pathSegments.push([point1, point2]]);
}

// Create the path by adding the path points and segments
var path = [];
path.push(pathPoints);
path.push(pathSegments);

// Set the path property of the shape layer to the calculated path
thisComp.layer("Shape Layer").path = path;
```

To use this expression, you need to:

1. Create a new shape layer in your composition.
2. Select the shape layer and go to the "Path" property.
3. Click on the "Expression" button next to the "Path" property.
4. Copy and paste the expression code into the expression editor.
5. Press "Enter" to save the expression.
6. Preview your composition to see the rounded square shape.

