    gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
    vTexCoord = texCoord;
}
```

Fragment Shader:

```glsl
#version 330

in vec2 vTexCoord;

uniform sampler2D texture;

out vec4 fragColor;

void main() {
    fragColor = textureLod(texture, vTexCoord, 0.0);
}
```

