    this.ctx = this.canvas.getcontext('2d');
    // set the initial selected frame
    this.selectedframe = 0;
  },
  drawsprite: function() {
    // draw the sprite on the canvas
    const sprite = this.sprite;
    const ctx = this.ctx;
    ctx.save();
    ctx.translate(sprite.frames[this.selectedframe]].x, sprite.frames[this.selectedframe]].y);
    ctx.scale(sprite.frames[this.selectedframe]].width, sprite.frames[this.selectedframe]].height);
    ctx.drawImage(sprite.frames[this.selectedframe]].image, 0, 0);
    ctx.restore();
  },
  selectframe: function(frameindex) {
    // select a frame in the sprite
    this.selectedframe = frameindex;
  },
  addframe: function() {
    // add a new frame to the sprite
    const sprite = this.sprite;
    const newframe = {
      x: 0,
      y: 0,
      width: sprite.width,
      height: sprite.height
    };
    sprite.frames.push(newframe);
  },
  removeframe: function(frameindex) {
    // remove a frame from the sprite
    const sprite = this.sprite;
    sprite.frames.splice(frameindex, 1);
  }
};

