To directly download a page using its URL in the browser console, you can use the following code:

```
var url = "https://www.example.com"; // replace with your URL
var xhr = new XMLHttpRequest();
xhr.open("GET", url, true);
xhr.responseType = "blob";
xhr.onload = function() {
  if (xhr.status === 200) {
    var blob = xhr.response;
    var url = window.URL.createObjectURL(blob);
    var a = document.createElement("a");
    a.href = url;
    a.download = "filename.html"; // replace with your desired filename
    a.click();
    window.URL.revokeObjectURL(url);
  }
};
xhr.send();
```

Replace the `url` variable with the URL of the page you want to download. You can also change the `a.download` variable to your desired filename.

When you run this code in the browser console, it will download the page as a file with the specified filename.

